/**
* Game Loop
*/
function gameLoop(timestamp) {
if (!mapData) {
requestAnimationFrame(gameLoop);
return;
}
if (state.isDead) {
updateCamera();
requestAnimationFrame(gameLoop);
return;
}
updateGame(timestamp);
updateHud();
updateCamera();
if (import.meta.env.DEV || debugEnabled) updateDebugStats();
requestAnimationFrame(gameLoop);
}
/**
* Initialization
*/
async function init() {
if (import.meta.env.DEV) { debugEnabled = true; initDebugMenu(); }
initKeyboardInput();
initMouseInput();
initTouchInput();
initGamepadInput();
await loadMap('E1M1');
startCullingLoop();
updateMenuSelection();
updateHud();
updateCamera();
await new Promise(resolve => setTimeout(resolve, 600));
hideInitialOverlay();
/* Start game loop */
requestAnimationFrame(gameLoop);
window.focus();
}
